module.render:
const size = args.size || '40px';
const color = args.color || 'var(--accent-color)';
const margin = args.margin || '1rem 0 0 0';
const direction = (args.direction || 'down').toLowerCase();
const shape = (args.shape || 'triangle').toLowerCase();
// Shapes are drawn pointing RIGHT (0deg); direction rotates the whole SVG.
const angles = {
  right: 0, 'down-right': 45, down: 90, 'down-left': 135,
  left: 180, 'up-left': 225, up: 270, 'up-right': 315
};
const angle = angles[direction] != null ? angles[direction] : 90;
const shapes = {
  triangle: '<polygon points="22,14 86,50 22,86"/>',
  chevron: '<polyline points="34,16 70,50 34,84" fill="none" stroke="currentColor" stroke-width="14" stroke-linecap="round" stroke-linejoin="round"/>',
  line: '<path d="M10 50 H72" fill="none" stroke="currentColor" stroke-width="12" stroke-linecap="round"/><polyline points="56,26 84,50 56,74" fill="none" stroke="currentColor" stroke-width="12" stroke-linecap="round" stroke-linejoin="round"/>',
  double: '<polyline points="20,18 52,50 20,82" fill="none" stroke="currentColor" stroke-width="13" stroke-linecap="round" stroke-linejoin="round"/><polyline points="48,18 80,50 48,82" fill="none" stroke="currentColor" stroke-width="13" stroke-linecap="round" stroke-linejoin="round"/>'
};
const inner = shapes[shape] || shapes.triangle;
return `\n\n<div class="mdp-mod-arrow-wrap" style="margin: ${margin};"><svg viewBox="0 0 100 100" class="mdp-mod-arrow-svg" style="width: ${size}; height: ${size}; color: ${color}; transform: rotate(${angle}deg);" fill="currentColor">${inner}</svg></div>\n\n`;
